+		} else {
+			len = min(BBSIZE, remaining);
 			/*
 			 * If this is MCI1 revision 2xx controller, apply
 			 * a work-around for the "Data Write Operation and
@@ -530,74 +769,75 @@ at91_mci_start_cmd(struct at91_mci_softc
